#include <stdio.h>
#include <limits.h>
int main() {
    int N, M, x;
    scanf("%d %d %d", &N, &M, &x);
    int S[N], T[M];
    for (int i = 0; i < N; i++) {
        scanf("%d", &S[i]);
    }
    for (int i = 0; i < M; i++) {
        scanf("%d", &T[i]);
    }
    int minS = INT_MAX, maxS = INT_MIN;
    int minT = INT_MAX, maxT = INT_MIN;
    for (int i = 0; i < N; i++) {
        minS = (S[i] < minS) ? S[i] : minS;
        maxS = (S[i] > maxS) ? S[i] : maxS;
    }
    for (int i = 0; i < M; i++) {
        minT = (T[i] < minT) ? T[i] : minT;
        maxT = (T[i] > maxT) ? T[i] : maxT;
    }
    int result = (maxS + maxT) - (minS + minT);
    printf("%d\n", result);
    return 0;
}

