import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();
        int x = scanner.nextInt();
        int[] S = new int[N];
        int[] T = new int[M];
        for (int i = 0; i < N; i++) {
            S[i] = scanner.nextInt();
        }
        for (int i = 0; i < M; i++) {
            T[i] = scanner.nextInt();
        }
        int minS = Integer.MAX_VALUE, maxS = Integer.MIN_VALUE;
        int minT = Integer.MAX_VALUE, maxT = Integer.MIN_VALUE;
        for (int i = 0; i < N; i++) {
            minS = Math.min(S[i], minS);
            maxS = Math.max(S[i], maxS);
        }
        for (int i = 0; i < M; i++) {
            minT = Math.min(T[i], minT);
            maxT = Math.max(T[i], maxT);
        }
        int result = (maxS + maxT) - (minS + minT);
        System.out.println(result);
    }
}

